ENTRY.C_GL:
var Mod;
var ccy;
var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
DV.writeLog("SYS_MODULE_NAME cr"+SYS_MODULE_NAME);
var country = DV.getCountryCode();
DV.writeLog("country"+country);
if(SYS_MODULE_NAME=='IMLC'){
        Mod = 'IL';
        ccy = DV.getFieldValue("LC_CCY");
   DV.writeLog("1"+ccy);
}
else if(SYS_MODULE_NAME=='IMCO')
{
 	Mod = 'IC';
         ccy = DV.appendField("COLL_CCY");
}
var item_name= Mod+'_'+ccy;
DV.writeLog("item_name"+item_name);
var sql = "item_c='012" + "'" + " and CNTY_CODE='" + country + "'" + " and ITEM_NAME='" + item_name + "'"; 
DV.writeLog("sql"+sql);
DV.SYS_getTableData('FIELD_1_X','eximtrx.data_master',sql);
DV.writeLog("2 sql");

ENTRY.C_CURRENCY:
var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
 if(SYS_MODULE_NAME=='IMLC'){
 var lc_ccy = DV.getFieldValue("LC_CCY");
 DV.appendField(lc_ccy);
 }
 else if(SYS_MODULE_NAME=='IMCO'){
 var COLL_CCY = DV.getFieldValue("COLL_CCY");
 DV.appendField(COLL_CCY);
 }

ENTRY.N_AMT:
var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
DV.writeLog("SYS_MODULE_NAME dr bal"+SYS_MODULE_NAME); 
var SYS_FUNCTION_NAME = DV.getFieldValue("CURRNT_STATUS");
var SYS_FUNCTION_NAME1 = DV.SYS_FUNCTION_NAME;
DV.writeLog("SYS_FUNCTION_NAME1"+SYS_FUNCTION_NAME1);
DV.writeLog("SYS_FUNCTION_NAME"+SYS_FUNCTION_NAME);
DV.writeLog("SYS_FUNCTION_NAME dr bal "+SYS_FUNCTION_NAME);
 if(SYS_MODULE_NAME=='IMLC'){
DV.writeLog("1");
    var LC_BAL = DV.getFieldValue("LC_BAL");
DV.writeLog("2"+LC_BAL);
    //DV.appendField(LC_BAL);
   if(SYS_FUNCTION_NAME=='Issued LC' || SYS_FUNCTION_NAME1=='IMLC_IssueLC'){
   DV.appendField( LC_BAL);

DV.writeLog(" LC_BAL"+ LC_BAL);
   }
   else if(SYS_FUNCTION_NAME=='IMLC_Amend' || SYS_FUNCTION_NAME1=="IMLC Amend After Registration"){
    var inc_amt=DV.toFloat(DV.getFieldValue("INC_LIAB_AMT"));
    var det_flg=DV.getFieldValue("DETRMNTL_FLG");
    if(inc_amt > 0 && det_flg =='No'){
        DV.appendField(inc_amt);
    }
   } 
  else if(SYS_FUNCTION_NAME=="Bene Accepts Amendment" || SYS_FUNCTION_NAME1=='Bene Accepts Amendment'){
    var inc_amt=DV.toFloat(DV.getFieldValue("INC_LIAB_AMT"));
    var det_flg=DV.getFieldValue("DETRMNTL_FLG");
    if(inc_amt > 0){
        DV.appendField(inc_amt);
    }
   }
   else
   {
     DV.appendField(LC_BAL);
   }
  }
  else if(SYS_MODULE_NAME=='IMCO'){
   var DRWG_AMT_CCY = DV.getFieldValue("DRWG_AMT_CCY");
  DV.appendField(DRWG_AMT_CCY);
  }

ENTRY.D_VALUE_DATE:
var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
 if(SYS_MODULE_NAME=='IMLC'){
  var ISSUE_DT = DV.getFieldValue("ISSUE_DT");
  DV.appendField(ISSUE_DT);
 }
 else if(SYS_MODULE_NAME=='IMCO'){
 var AVLI_DATE = DV.getFieldValue("AVLI_DATE");
 DV.appendField(AVLI_DATE);
 }

ENTRY.C_EXCHGE_RATE2:
var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
var ccy1; 
var baseCCY =DV.SYS_LCY ;
var defaultRate = '1';
var cnty = DV.getCountryCode();
  if(SYS_MODULE_NAME=='IMLC'){
  ccy1 = DV.getFieldValue("LC_CCY");
  }
  else if(SYS_MODULE_NAME=='IMCO'){
  ccy1 = DV.getFieldValue("COLL_CCY");
  }
if(ccy1!= null){
  if(ccy1 != baseCCY){
	sql = "C_FROM_CCY = '"+ ccy1 +"' AND C_TO_CCY='"+baseCCY+"' and C_BK_GROUP_ID='STBANK' and C_CNTY_CODE='"+cnty+"' and C_DESC_ID='TT Buying' "; 	
	DV.SYS_getTableData('F_VALUE','EXIMSYS.STD_EXCHAN_RATE',sql);
  }else{
	DV.appendField(defaultRate);
  }
}else{
	DV.appendField(defaultRate);
}

