ENTRY.C_GL:
var ccy;
 var Mod;
 var SYS_MODULE_NAME = DV.SYS_MODULE_NAME;
DV.writeLog("SYS_MODULE_NAME om"+SYS_MODULE_NAME);
DV.writeLog("9");
 var country = DV.getCountryCode(); 
DV.writeLog("2");
 var c_cust_id = DV.getFieldValue("C_CUST_ID");
DV.writeLog("country dr"+country);
 if(SYS_MODULE_NAME=='IMLC'){
    c_cust_id = DV.getFieldValue("APPL_ID");
    DV.writeLog("c_cust_id"+c_cust_id);
    Mod = 'IL';
    ccy = DV.getFieldValue("LC_CCY");
 }
 else if(SYS_MODULE_NAME=='IMCO')
 {
     c_cust_id = DV.getFieldValue("DRWE_ID");
     Mod = 'IC';
     ccy = DV.getFieldValue("COLL_CCY");
 }
 var item_name= Mod+'C';
 var c_cr_dr = 'L';
 DV.writeLog("item_name"+item_name);
 DV.writeLog("c_cr_dr"+c_cr_dr);
var sql = "c_cl_fcty_type='" + item_name + "'"  + " and c_cust_id='"+ c_cust_id + "'" + " and C_CNTY_CODE='" + country + "'" + " and ";
sql = sql + "C_CURRENCY='" + ccy + "'" + "and C_DBT_CRDT='" +c_cr_dr+ "'"; 
DV.SYS_getTableData('C_AC_NUMBER','eximsys.std_ac_number',sql);

